// Parse HTML table da conta fixa
const input = $input.first().json;
let extracted = [];

try {
  const htmlContent = input.xml_ref || '';
  if (!htmlContent.includes('table-contas-fixas')) {
    throw new Error('Tabela de contas fixas não encontrada');
  }

  // Regex para extrair linhas da tabela
  const rowPattern = /<tr[^>]*class="table-row-body"[^>]*codigo="([^"]+)"[^>]*>(.*?)<\/tr>/gs;
  let match;

  while ((match = rowPattern.exec(htmlContent)) !== null) {
    const codigo = match[1];
    const rowContent = match[2];

    // Extrair células da linha
    const cellPattern = /<td[^>]*class="table-item-body"[^>]*>(.*?)<\/td>/gs;
    const cells = [];
    let cellMatch;

    while ((cellMatch = cellPattern.exec(rowContent)) !== null) {
      const cellContent = cellMatch[1].replace(/<[^>]*>/g, '').trim();
      cells.push(cellContent);
    }

    if (cells.length >= 6) {
      const dataVencimento = cells[0] || '';
      const historico = cells[1] || '';
      const valor = cells[2] || '0';
      const situacao = cells[3] || '';
      const tipoPagamento = cells[4] || '';
      const conta = cells[5] || '';

      // Parse de valor
      const valorNumerico = parseFloat(
        valor.replace('R$', '').replace(/\./g, '').replace(',', '.').trim()
      ) || 0;

      extracted.push({
        codigo: codigo,
        data_vencimento: dataVencimento,
        historico: historico,
        valor: valorNumerico,
        situacao: situacao,
        tipo_pagamento: tipoPagamento,
        conta: conta
      });
    }
  }

  if (extracted.length === 0) {
    throw new Error('Nenhuma conta fixa extraída da tabela');
  }

} catch (error) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'regular_bills',
    event: 'parse_error',
    message: error.message,
    level: 'error'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'Parse error', details: error.message }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'regular_bills',
  event: 'data_extract_success',
  count: extracted.length,
  level: 'info'
}));

return { extracted };

// Sucesso
const result = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'regular_bills',
  event: 'upsert_success',
  affected_rows: result.affectedRows || 0,
  level: 'info'
}));

return {
  statusCode: 201,
  body: { 
    ok: true, 
    message: 'Data extracted, cleaned, and converted to DataFrame successfully' 
  }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'regular_bills',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not process regular bills' }
};
